function formatTZS(amount) {
  return `TZS ${amount.toLocaleString("en-US")}`;
}
function formatDate(dateStr) {
  return new Date(dateStr).toLocaleDateString("en-GB", {
    year: "numeric",
    month: "short",
    day: "numeric"
  });
}
function formatDateTime(dateStr) {
  return new Date(dateStr).toLocaleString("en-GB", {
    year: "numeric",
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit"
  });
}
function generateId() {
  return crypto.randomUUID();
}
function statusColor(status) {
  switch (status) {
    case "approved":
      return "bg-green-100 text-green-800";
    case "rejected":
      return "bg-red-100 text-red-800";
    case "pending":
      return "bg-yellow-100 text-yellow-800";
    default:
      return "bg-gray-100 text-gray-800";
  }
}
function serviceLabel(type) {
  switch (type) {
    case "cash_send":
      return "Cash Send";
    case "cash_withdrawal":
      return "Cash Withdrawal";
    case "airtime_bundle":
      return "Airtime/Bundle";
    case "tv_subscriptions":
      return "TV Subscriptions";
    case "internet_subscriptions":
      return "Internet Subscriptions";
    case "utility_bills":
      return "Utility Bills/Services";
    case "all_payments":
      return "All Payment Bills";
    default:
      return type;
  }
}
function carrierLabel(carrier) {
  return carrier;
}
function tierLabel(tier) {
  switch (tier) {
    case "d2d":
      return "Day-to-Day";
    case "premier":
      return "Premier";
    default:
      return tier;
  }
}
